@startuml
title LIGHT's Class Diagram

package "android" {
  package "view" {
    package "View" {
      class OnClickListener <<C>>
    }
  }
  package "widget" {
    package "CompoundButton" {
      class OnCheckedChangeListener <<C>>
    }
  }
}

package "androidx" {
  package "appcompat" {
    package "app" {
      class AppCompatActivity <<C>>
    }
  }
}

package "com" {
  package "example" {
    package "light" {
      class BuildConfig <<C>>
      class MainActivity <<C>>
    }
  }
}

MainActivity ..|> OnCheckedChangeListener
MainActivity ..|> OnClickListener
MainActivity --|> AppCompatActivity

@enduml
